class ServiceState:
    """Tracks internal state of the service for debugging purposes."""

    def __init__(self):
        self._lock = threading.Lock()
        self.start_time = datetime.utcnow().isoformat()
        self.request_count = 0
        self.error_count = 0
        self.last_error = None
        self.last_error_time = None
        self.active_requests = 0
        self.peak_active_requests = 0
        self.method_stats = {}
        self.recent_errors = []
        self.max_recent_errors = 50
        self._db_connected = True
        self._cache_connected = True

    def record_request(self, method_name):
        with self._lock:
            self.request_count += 1
            self.active_requests += 1
            self.peak_active_requests = max(self.peak_active_requests, self.active_requests)
            if method_name not in self.method_stats:
                self.method_stats[method_name] = {
                    "total_calls": 0,
                    "errors": 0,
                    "last_call": None,
                    "avg_duration_ms": 0,
                    "total_duration_ms": 0,
                }
            self.method_stats[method_name]["total_calls"] += 1
            self.method_stats[method_name]["last_call"] = datetime.utcnow().isoformat()

    def record_request_complete(self, method_name, duration_ms):
        with self._lock:
            self.active_requests -= 1
            if method_name in self.method_stats:
                stats = self.method_stats[method_name]
                stats["total_duration_ms"] += duration_ms
                stats["avg_duration_ms"] = (
                    stats["total_duration_ms"] / stats["total_calls"]
                )

    def record_error(self, method_name, error_info):
        with self._lock:
            self.error_count += 1
            self.last_error = error_info
            self.last_error_time = datetime.utcnow().isoformat()
            if method_name in self.method_stats:
                self.method_stats[method_name]["errors"] += 1
            self.recent_errors.append({
                "time": self.last_error_time,
                "method": method_name,
                "error": error_info,
            })
            if len(self.recent_errors) > self.max_recent_errors:
                self.recent_errors = self.recent_errors[-self.max_recent_errors:]

    def to_dict(self, component=None):
        with self._lock:
            state = {
                "service": {
                    "start_time": self.start_time,
                    "uptime_seconds": (
                        datetime.utcnow() - datetime.fromisoformat(self.start_time)
                    ).total_seconds(),
                    "request_count": self.request_count,
                    "error_count": self.error_count,
                    "error_rate": (
                        self.error_count / self.request_count
                        if self.request_count > 0
                        else 0
                    ),
                    "active_requests": self.active_requests,
                    "peak_active_requests": self.peak_active_requests,
                },
                "last_error": {
                    "info": self.last_error,
                    "time": self.last_error_time,
                },
                "method_stats": self.method_stats,
                "recent_errors": self.recent_errors[-10:],
                "system": {
                    "python_version": sys.version,
                    "platform": platform.platform(),
                    "pid": os.getpid(),
                    "thread_count": threading.active_count(),
                },
                "dependencies": {
                    "database": "connected" if self._db_connected else "disconnected",
                    "cache": "connected" if self._cache_connected else "disconnected",
                },
            }
            if component and component in state:
                return {component: state[component]}
            return state


def build_error_detail(
    method_name,
    exception,
    request_info=None,
    service_state=None,
    additional_context=None,
):
    """Build a comprehensive error detail message for gRPC responses."""
    error_detail = {
        "error_type": type(exception).__name__,
        "error_message": str(exception),
        "method": method_name,
        "timestamp": datetime.utcnow().isoformat() + "Z",
        "traceback": traceback.format_exception(
            type(exception), exception, exception.__traceback__
        ),
        "stack_frames": [],
    }

    # Extract detailed stack frame information
    tb = exception.__traceback__
    while tb is not None:
        frame = tb.tb_frame
        frame_info = {
            "filename": frame.f_code.co_filename,
            "function": frame.f_code.co_name,
            "line_number": tb.tb_lineno,
            "local_variables": {},
        }
        # Capture local variables (sanitized)
        for key, value in frame.f_locals.items():
            if key.startswith("_"):
                continue
            try:
                # Avoid serializing large or sensitive objects
                val_str = repr(value)
                if len(val_str) > 500:
                    val_str = val_str[:500] + "...<truncated>"
                frame_info["local_variables"][key] = val_str
            except Exception:
                frame_info["local_variables"][key] = "<unserializable>"
        error_detail["stack_frames"].append(frame_info)
        tb = tb.tb_next

    if request_info:
        error_detail["request_info"] = request_info

    if service_state:
        error_detail["service_state_snapshot"] = service_state.to_dict()

    if additional_context:
        error_detail["additional_context"] = additional_context

    # Add chain of exceptions if present
    if exception.__cause__:
        error_detail["caused_by"] = {
            "error_type": type(exception.__cause__).__name__,
            "error_message": str(exception.__cause__),
            "traceback": traceback.format_exception(
                type(exception.__cause__),
                exception.__cause__,
                exception.__cause__.__traceback__,
            ),
        }

    return error_detail


def error_handler(method_name, service_state):
    """Decorator for gRPC service methods that provides comprehensive error handling."""

    def decorator(func):
        def wrapper(self, request, context):
            start_time = time.time()
            service_state.record_request(method_name)

            # Extract request info for debugging
            request_info = {}
            try:
                for field in request.DESCRIPTOR.fields:
                    request_info[field.name] = getattr(request, field.name)
            except Exception:
                request_info = {"raw": str(request)}

            try:
                result = func(self, request, context)
                duration_ms = (time.time() - start_time) * 1000
                service_state.record_request_complete(method_name, duration_ms)
                return result

            except grpc.RpcError:
                # Re-raise gRPC errors that were intentionally set
                duration_ms = (time.time() - start_time) * 1000
                service_state.record_request_complete(method_name, duration_ms)
                raise

            except ValueError as e:
                duration_ms = (time.time() - start_time) * 1000
                service_state.record_request_complete(method_name, duration_ms)

                error_detail = build_error_detail(
                    method_name,
                    e,
                    request_info=request_info,
                    service_state=service_state,
                    additional_context={
                        "category": "VALIDATION_ERROR",
                        "duration_ms": duration_ms,
                        "suggestion": "Check request parameters for validity",
                    },
                )

                error_json = json.dumps(error_detail, indent=2, default=str)
                service_state.record_error(method_name, error_detail)

                context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
                context.set_details(error_json)

                # Add trailing metadata with error summary
                context.set_trailing_metadata([
                    ("x-error-type", type(e).__name__),
                    ("x-error-method", method_name),
                    ("x-error-timestamp", datetime.utcnow().isoformat()),
                    ("x-debug-request-count", str(service_state.request_count)),
                ])

                return _get_default_response(method_name)

            except KeyError as e:
                duration_ms = (time.time() - start_time) * 1000
                service_state.record_request_complete(method_name, duration_ms)

                error_detail = build_error_detail(
                    method_name,
                    e,
                    request_info=request_info,
                    service_state=service_state,
                    additional_context={
                        "category": "NOT_FOUND_ERROR",
                        "duration_ms": duration_ms,
                        "suggestion": "The requested resource was not found in the data store",
                    },
                )

                error_json = json.dumps(error_detail, indent=2, default=str)
                service_state.record_error(method_name, error_detail)

                context.set_code(grpc.StatusCode.NOT_FOUND)
                context.set_details(error_json)

                context.set_trailing_metadata([
                    ("x-error-type", type(e).__name__),
                    ("x-error-method", method_name),
                    ("x-error-timestamp", datetime.utcnow().isoformat()),
                ])

                return _get_default_response(method_name)

            except PermissionError as e:
                duration_ms = (time.time() - start_time) * 1000
                service_state.record_request_complete(method_name, duration_ms)

                error_detail = build_error_detail(
                    method_name,
                    e,
                    request_info=request_info,
                    service_state=service_state,
                    additional_context={
                        "category": "PERMISSION_ERROR",
                        "duration_ms": duration_ms,
                    },
                )

                error_json = json.dumps(error_detail, indent=2, default=str)
                service_state.record_error(method_name, error_detail)

                context.set_code(grpc.StatusCode.PERMISSION_DENIED)
                context.set_details(error_json)

                context.set_trailing_metadata([
                    ("x-error-type", type(e).__name__),
                    ("x-error-method", method_name),
                    ("x-error-timestamp", datetime.utcnow().isoformat()),
                ])

                return _get_default_response(method_name)

            except ConnectionError as e:
                duration_ms = (time.time() - start_time) * 1000
                service_state.record_request_complete(method_name, duration_ms)

                error_detail = build_error_detail(
                    method_name,
                    e,
                    request_info=request_info,
                    service_state=service_state,
                    additional_context={
                        "category": "DEPENDENCY_ERROR",
                        "duration_ms": duration_ms,
                        "suggestion": "A downstream dependency is unavailable. Check database/cache connections.",
                    },
                )

                error_json = json.dumps(error_detail, indent=2, default=str)
                service_state.record_error(method_name, error_detail)

                context.set_code(grpc.StatusCode.UNAVAILABLE)
                context.set_details(error_json)

                context.set_trailing_metadata([
                    ("x-error-type", type(e).__name__),
                    ("x-error-method", method_name),
                    ("x-error-timestamp", datetime.utcnow().isoformat()),
                ])

                return _get_default_response(method_name)

            except TimeoutError as e:
                duration_ms = (time.time() - start_time) * 1000
                service_state.record_request_complete(method_name, duration_ms)

                error_detail = build_error_detail(
                    method_name,
                    e,
                    request_info=request_info,
                    service_state=service_state,
                    additional_context={
                        "category": "TIMEOUT_ERROR",
                        "duration_ms": duration_ms,
                        "suggestion": "Operation timed out. Consider increasing timeout or optimizing the operation.",
                    },
                )

                error_json = json.dumps(error_detail, indent=2, default=str)
                service_state.record_error(method_name, error_detail)

                context.set_code(grpc.StatusCode.DEADLINE_EXCEEDED)
                context.set_details(error_json)

                context.set_trailing_metadata([
                    ("x-error-type", type(e).__name__),
                    ("x-error-method", method_name),
                    ("x-error-timestamp", datetime.utcnow().isoformat()),
                ])

                return _get_default_response(method_name)

            except Exception as e:
                duration_ms = (time.time() - start_time) * 1000
                service_state.record_request_complete(method_name, duration_ms)

                error_detail = build_error_detail(
                    method_name,
                    e,
                    request_info=request_info,
                    service_state=service_state,
                    additional_context={
                        "category": "INTERNAL_ERROR",
                        "duration_ms": duration_ms,
                        "suggestion": "An unexpected error occurred. Check service logs and state for more details.",
                    },
                )

                error_json = json.dumps(error_detail, indent=2, default=str)
                service_state.record_error(method_name, error_detail)

                context.set_code(grpc.StatusCode.INTERNAL)
                context.set_details(error_json)

                context.set_trailing_metadata([
                    ("x-error-type", type(e).__name__),
                    ("x-error-method", method_name),
                    ("x-error-timestamp", datetime.utcnow().isoformat()),
                    ("x-debug-error-count", str(service_state.error_count)),
                ])

                return _get_default_response(method_name)

        return wrapper

    return decorator


def _get_default_response(method_name):
    """Return a default (empty) response for the given method on error."""
    response_map = {
        "GetUser": debug_service_pb2.UserResponse,
        "ProcessOrder": debug_service_pb2.OrderResponse,
        "HealthCheck": debug_service_pb2.HealthResponse,
        "GetServiceState": debug_service_pb2.StateResponse,
    }
    response_class = response_map.get(method_name)
    if response_class:
        return response_class()
    return None


