USERS_DB = {
    "user_1": {"name": "Alice Johnson", "email": "alice@example.com"},
    "user_2": {"name": "Bob Smith", "email": "bob@example.com"},
    "user_3": {"name": "Charlie Brown", "email": "charlie@example.com"},
}

ORDERS_DB = {}

# Global service state
service_state = ServiceState()


class DebugServiceServicer(debug_service_pb2_grpc.DebugServiceServicer):
    """gRPC service implementation with comprehensive error handling."""

    def __init__(self):
        self._state = service_state
        self._simulate_db_failure = False
        self._simulate_slow_query = False

    @error_handler("GetUser", service_state)
    def GetUser(self, request, context):
        """Get user by ID with detailed error handling."""
        user_id = request.user_id

        # Validation
        if not user_id:
            raise ValueError("user_id is required and cannot be empty")

        if not user_id.startswith("user_"):
            raise ValueError(
                f"Invalid user_id format: '{user_id}'. Expected format: 'user_<number>'"
            )

        # Simulate DB connection issue
        if self._simulate_db_failure:
            raise ConnectionError(
                "Failed to connect to PostgreSQL at db.internal:5432 - Connection refused"
            )

        # Simulate slow query timeout
        if self._simulate_slow_query:
            raise TimeoutError(
                "Database query timed out after 30s: SELECT * FROM users WHERE id = ?"
            )

        # Lookup user
        if user_id not in USERS_DB:
            raise KeyError(
                f"User with id '{user_id}' not found in database. "
                f"Available users: {list(USERS_DB.keys())}"
            )

        user = USERS_DB[user_id]
        return debug_service_pb2.UserResponse(
            user_id=user_id,
            name=user["name"],
            email=user["email"],
        )

    @error_handler("ProcessOrder", service_state)
    def ProcessOrder(self, request, context):
        """Process an order with detailed error handling."""
        order_id = request.order_id
        user_id = request.user_id
        amount = request.amount

        # Validation
        if not order_id:
            raise ValueError("order_id is required")

        if not user_id:
            raise ValueError("user_id is required")

        if amount <= 0:
            raise ValueError(
                f"Invalid order amount: {amount}. Amount must be positive."
            )

        if amount > 10000:
            raise PermissionError(
                f"Order amount ${amount:.2f} exceeds the maximum allowed "
                f"single transaction limit of $10,000.00. "
                f"Please contact admin for high-value transactions."
            )

        # Check user exists
        if user_id not in USERS_DB:
            raise KeyError(
                f"Cannot process order for non-existent user '{user_id}'"
            )

        # Simulate a processing error for specific order IDs
        if order_id == "order_fail":
            # This simulates an unexpected internal error
            data = {"items": None}
            # This will raise a TypeError
            total = sum(data["items"])  # noqa: F841 - intentional error for demo

        if order_id == "order_divide":
            # Simulate division by zero
            discount_rate = 0
            final_amount = amount / discount_rate  # noqa: F841

        # Process the order
        ORDERS_DB[order_id] = {
            "user_id": user_id,
            "amount": amount,
            "status": "PROCESSED",
            "timestamp": datetime.utcnow().isoformat(),
        }

        return debug_service_pb2.OrderResponse(
            order_id=order_id,
            status="PROCESSED",
            message=f"Order {order_id} processed successfully for ${amount:.2f}",
        )

    @error_handler("HealthCheck", service_state)
    def HealthCheck(self, request, context):
        """Health check endpoint with optional details."""
        status = "HEALTHY"
        details = {}

        if request.include_details:
            details = {
                "uptime_seconds": (
                    datetime.utcnow() - datetime.fromisoformat(self._state.start_time)
                ).total_seconds(),
                "request_count": self._state.request_count,
                "error_count": self._state.error_count,
                "active_requests": self._state.active_requests,
                "dependencies": {
                    "database": "connected" if self._state._db_connected else "disconnected",
                    "cache": "connected" if self._state._cache_connected else "disconnected",
                },
            }

            if not self._state._db_connected or not self._state._cache_connected:
                status = "DEGRADED"

            if self._state.error_count > 0 and self._state.request_count > 0:
                error_rate = self._state.error_count / self._state.request_count
                if error_rate > 0.5:
                    status = "UNHEALTHY"
                    details["warning"] = f"High error rate: {error_rate:.2%}"

        return debug_service_pb2.HealthResponse(
            status=status,
            details=json.dumps(details, indent=2) if details else "",
        )

    @error_handler("GetServiceState", service_state)
    def GetServiceState(self, request, context):
        """Get detailed internal service state for debugging."""
        component = request.component if request.component else None
        state_dict = self._state.to_dict(component=component)

        return debug_service_pb2.StateResponse(
            state_json=json.dumps(state_dict, indent=2, default=str),
        )


def serve(port=50051):
    """Start the gRPC server."""
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=10),
        options=[
            ("grpc.max_send_message_length", 50 * 1024 * 1024),
            ("grpc.max_receive_message_length", 50 * 1024 * 1024),
        ],
    )
    debug_service_pb2_grpc.add_DebugServiceServicer_to_server(
        DebugServiceServicer(), server
    )
    server.add_insecure_port(f"[::]:{port}")
    server.start()
    print(f"Debug gRPC Service started on port {port}")
    print(f"Service PID: {os.getpid()}")
    print(f"Python version: {sys.version}")
    return server


